#!/bin/bash
# FIX_PROXY_v4.sh - Ajoute yt-dlp comme strategie supplementaire
set -e
cd /opt/clip-scraper

echo "============================================================"
echo "  FIX PROXY v4 - yt-dlp + regex fallback"
echo "============================================================"

B64=''
echo "$B64" | base64 -d > /opt/clip-scraper/scrapers/tiktok.py
echo "[OK] tiktok.py v4 ($(wc -c < /opt/clip-scraper/scrapers/tiktok.py) octets)"

echo "[..] Install yt-dlp dans le container..."
docker exec clip-scraper pip install --quiet yt-dlp 2>&1 | tail -3
echo "[OK] yt-dlp installe"

docker cp /opt/clip-scraper/scrapers/tiktok.py clip-scraper:/app/scrapers/tiktok.py
docker compose restart
sleep 25

echo ""
echo "[TEST] Scrape ethanduvinbuisness..."
curl -s -X POST "http://localhost:8001/v1/tiktok/ethanduvinbuisness?max_videos=20" -H "X-API-Key: cd-prod-ac29858a696cf2c1a642dd1c9f607628fcd8b0878cc3c704" --max-time 90 | head -c 2000
echo ""
echo ""
echo "[LOGS]"
docker logs clip-scraper --tail 20 2>&1
